// AUTO-GENERATED from samples/templates/Copy of BW Evaluation Form - google doc.docx
// via scripts/parse-chart.ts → scripts/generate-ranges-ts.ts. Hand-edits are fine;
// re-running the generator will overwrite this file.
//
// canonicalName preserves the doctor's exact wording from her master chart
// (including the 'Apoliopoprotein B' typo). The Apolipoprotein B correct spelling
// is included as an alias.

export interface InterpretationBand {
  label: string;                          // e.g. "Negative", "Optimal", "Moderate", "High", "Equivocal", "Positive"
  min: number | null;
  max: number | null;
  severity: "normal" | "borderline" | "abnormal";
}

/** How the flagging engine should evaluate this marker. See lib/flagging/. */
export type FlagType =
  | "optimal_two_tier"   // optimal range exists; flag if value falls outside it
  | "lab_range_only"     // no optimal range; flag against labRange only
  | "three_tier_band"    // Optimal/Moderate/High bands (see interpretationBands)
  | "categorical";       // value is a string; match against expectedValue

export interface MarkerRange {
  canonicalName: string;
  aliases: string[];
  unit: string;
  labRange: { min: number | null; max: number | null };
  optimalRange: { min: number | null; max: number | null };
  optimalRangeBySex?: {
    male: { min: number | null; max: number | null };
    female: { min: number | null; max: number | null };
  };
  interpretationBands?: InterpretationBand[];     // 3-zone markers (e.g. EBV antibodies, cardiac panel)
  panelType?: "standard" | "food_sensitivity";    // marks variable per-patient panels
  requiresConfirmation?: boolean;                 // true = doctor must verify before tool uses range
  confirmationSource?: string | null;             // citation for proposed/derived ranges
  confirmationNotes?: string;                     // context for the doctor when reviewing
  flagType: FlagType;                             // drives the flagging engine
  expectedValue?: string;                         // categorical markers (e.g. "Negative", "A")
  bandDirection?: "higher_is_worse" | "higher_is_better"; // three_tier_band orientation
  cyclePhaseDependent?: boolean;                  // hormones — flagged against widest range in v1
  flaggedAboveCutoff?: boolean;                   // lab_range_only with single upper cutoff (e.g. EBV)
  category: string;
  increaseCauses: string[];
  decreaseCauses: string[];
  notes?: string | null;                          // optional context for edge cases
  /** @deprecated use `notes` instead. Kept for backward compatibility. */
  note?: string;
}

