// Reverse lookup: given any alias (case-insensitive), find the canonical record.
const ALIAS_INDEX = (() => {
  const idx = new Map<string, MarkerRange>();
  for (const rec of Object.values(OPTIMAL_RANGES)) {
    idx.set(rec.canonicalName.toLowerCase(), rec);
    for (const a of rec.aliases) idx.set(a.toLowerCase(), rec);
  }
  return idx;
})();

export interface FoundMarker extends MarkerRange {
  /** True when the marker is still missing a confirmationSource (or carries
   *  the legacy requiresConfirmation flag). Callers should attach a
   *  "range pending confirmation from Melissa" note when flagging. */
  isUnconfirmed: boolean;
}

export function findMarker(name: string): FoundMarker | undefined {
  const rec = ALIAS_INDEX.get(name.toLowerCase().trim());
  if (!rec) return undefined;
  return { ...rec, isUnconfirmed: isUnconfirmed(rec) };
}

/** A marker is "unconfirmed" when it explicitly opted in via the legacy
 *  requiresConfirmation flag (and didn't yet supply a confirmationSource).
 *  Post-2026-05-27 refactor, none of the bundled markers should hit this
 *  branch — it remains as a safety net for future additions. */
export function isUnconfirmed(marker: MarkerRange): boolean {
  if (marker.requiresConfirmation !== true) return false;
  return !marker.confirmationSource;
}

/**
 * Returns false only for markers whose ranges are explicitly still pending
 * confirmation (legacy requiresConfirmation + missing source). The flagging
 * engine should still flag these but attach a "pending confirmation" note.
 */
export function isRangeUsable(marker: MarkerRange): boolean {
  return !isUnconfirmed(marker);
}
